const fs = require('fs');
const path = require('path');

// 列出项目根目录结构
function listDir(dir, depth = 0, maxDepth = 3) {
    if (depth > maxDepth) return '';
    let result = '';
    try {
        const items = fs.readdirSync(dir);
        for (const item of items) {
            if (item.startsWith('.') || item === 'node_modules') continue;
            const fullPath = path.join(dir, item);
            const stat = fs.statSync(fullPath);
            const indent = '  '.repeat(depth);
            if (stat.isDirectory()) {
                result += `${indent}📁 ${item}/\n`;
                result += listDir(fullPath, depth + 1, maxDepth);
            } else {
                const size = stat.size > 1024 ? `${(stat.size / 1024).toFixed(1)}KB` : `${stat.size}B`;
                result += `${indent}📄 ${item} (${size})\n`;
            }
        }
    } catch(e) {
        result += `  [无法读取: ${e.message}]\n`;
    }
    return result;
}

console.log("=== 项目根目录结构 ===\n");
console.log(listDir(process.cwd()));

// 读取 package.json
try {
    const pkg = JSON.parse(fs.readFileSync('package.json', 'utf-8'));
    console.log('=== package.json ===');
    console.log(`名称: ${pkg.name || '未设置'}`);
    console.log(`版本: ${pkg.version || '未设置'}`);
    console.log(`描述: ${pkg.description || '未设置'}`);
    console.log(`入口: ${pkg.main || '未设置'}`);
    if (pkg.scripts) {
        console.log('脚本:');
        Object.entries(pkg.scripts).forEach(([k, v]) => console.log(`  ${k}: ${v}`));
    }
} catch(e) {
    console.log('无 package.json 或读取失败');
}

// 读取 README
try {
    const readme = fs.readFileSync('README.md', 'utf-8');
    console.log('\n=== README.md (前800字符) ===');
    console.log(readme.substring(0, 800));
} catch(e) {
    console.log('无 README.md');
}
